VALUES
  ('heelevel3-988e0de1-moex-00009', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '有關查核人員評估不實表達對財務報表之影響，下列敘述何者錯誤？', '["未更正不實表達不包含顯然微小之不實表達", "查核人員於評估不實表達對財務報表之影響前，不得修正規劃階段決定之重大性", "即使分類之不實表達超過用以評估其他不實表達之重大性，查核人員仍可能作出就財務報 表整體而言該項分類之不實表達非屬重大之結論", "應考量以前期間不重大未更正不實表達之累計數對當期財務報表之影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00010', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '有關查核人員就查核財務報表時所辨認之內部控制缺失與治理單位及管理階層溝通之敘述， 下列何者正確？', '["查核人員依其專業判斷認為以口頭與治理單位溝通內部控制顯著缺失並不適當時，應以書 面為之", "影響相同科目餘額、揭露、攸關聲明之控制或內部控制組成要素存有多項缺失不足以構成 顯著缺失", "以往查核曾與治理單位及管理階層溝通之內部控制顯著缺失未經改正，查核人員詢問管理 階層該等缺失尚未改正之原因獲合理之解釋，則無須於當期重複溝通", "查核人員於解釋內部控制顯著缺失之潛在影響時無須予以量化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00011', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '查核人員於查核規劃階段使用分析性程序的主要目的為何？①協助評估受查者繼續經營能力', '["協助查核人員瞭解受查者之產業及其環境", "辨認並評估可能的重大不實表達風險", "減 少詳細的測試", "僅"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00012', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '查核人員為因應管理階層踰越控制之風險，下列何者並非必要的查核程序？', '["測試會計分錄及編製財務報表所作其他調整之適當性", "複核管理階層作會計估計時是否偏頗，並評估造成該偏頗之情況是否顯示存有導因於舞弊 之重大不實表達風險", "就其所辨認之不尋常或非正常營運之重大交易，評估交易之動機及合理性是否顯示該等交 易之進行係用以從事財務報導舞弊或掩飾挪用資產", "對因應管理階層踰越控制風險之控制，執行控制測試"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00013', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '依審計準則規定，繼任會計師應於接受委任前向前任會計師查詢有關委任人之資訊，其主要 目的為何？', '["允許前任會計師將客戶機密性的資訊揭露予擬繼任之會計師", "方便繼任會計師評估客戶管理階層的正直性", "協助繼任會計師評估是否接受該委任案", "詢問委任人更換會計師的理由，及過去收取的公費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00014', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列何者最不可能是查核人員兼採控制測試及證實程序之併用方式查核策略的原因？', '["查核人員預期受查者之內部控制制度設計良好，且能有效運作", "今年度交易大多為例行性交易，且受查者對於處理例行性交易有良好的控制程序", "為進一步瞭解內部控制並執行控制測試之成本，大於因而執行較少之證實測試可節省之成本", "受查者資訊系統已高度電腦化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00015', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '依據審計準則580號「書面聲明」之規定，下列敘述何者錯誤？', '["書面聲明是必要查核證據，受查者不提供或認為管理階層所出具之書面聲明不可靠時，會 計師應對財務報表出具無法表示意見之查核報告", "於某些情況下，查核人員可接受管理階層於書面聲明中使用「就本公司所知」之限制性文字", "為所要求書面聲明之目的，查核人員可與管理階層溝通顯然微小門檻", "管理階層對已履行其編製財務報表責任之書面聲明不可敘明「除某重大事項未遵循適用之 財務報導架構外，其已依該架構編製財務報表」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00016', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列何者係屬統計抽樣之選取樣本方法？', '["隨機抽樣（random sampling）", "隨意抽樣（hapharzardsampling）", "集群抽樣（blocksampling）", "判斷抽樣（directedsampling）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00017', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '公司送交股東的年報中，除了財務報表及查核報告之外，尚包括其他資訊。有關查核人員對 「其他資訊」責任之敘述，下列何者正確？', '["查核人員無義務閱讀「其他資訊」", "查核人員無義務查證「其他資訊」，但仍應閱讀「其他資訊」以確定其與財務報表是否有重 大的不一致", "查核人員應擴大查核程序，以驗證「其他資訊」", "查核人員應於查核報告的其他事項段，述明「其他資訊未經查核」或「查核報告未涵蓋其 他資訊」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL),
  ('heelevel3-988e0de1-moex-00018', 'heelevel3-988e0de1', 'heelevel3-988e0de1-moex-112-0e802df0', 'sub-heelevel3-988e0de1-01', NULL, 'single_choice', '下列查核程序，何者適合於查核訴訟與索賠事項之完整性聲明？①將財務報表與期後最近之', '["查閱至外勤工作結束日止之董事會及其他重要會議之議事錄", "複核有關賠償損失項目", "向受查者管理階層取得未決法律案件清單", "僅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:25+00:00", "source_pdf_sha1": "1731d19687e2", "answer_pdf_sha1": "4372d45127c4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "326", "s": "1107", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財務審計"}'::jsonb, NULL)
